
-- Table: public.product_migracion2

-- DROP TABLE IF EXISTS public.product_migracion2;

CREATE TABLE IF NOT EXISTS public.product_migracion
(
    referencia character varying(100) COLLATE pg_catalog."default",
    descripcion character varying(255) COLLATE pg_catalog."default",
    codigo character varying(50) COLLATE pg_catalog."default",
    cod_barras_1 character varying(50) COLLATE pg_catalog."default",
    cod_barras_2 character varying(50) COLLATE pg_catalog."default",
    cod_barras_3 character varying(50) COLLATE pg_catalog."default",
    descripcion_adicional text COLLATE pg_catalog."default",
    marca character varying(100) COLLATE pg_catalog."default",
    categoria_nombre character varying(150) COLLATE pg_catalog."default",
    seccion_nombre character varying(150) COLLATE pg_catalog."default",
    subseccion_nombre character varying(150) COLLATE pg_catalog."default",
    brand_nombre character varying(100) COLLATE pg_catalog."default"
)

TABLESPACE pg_default;

ALTER TABLE IF EXISTS public.product_migracion
    OWNER to postgres;







    -- =============================================
-- 3. Insertar en la tabla products de producción
-- =============================================
    id,                      -- UUID generado automáticamente
    category_id,
    section_id,
    sub_section_id,
    codigo,
    referencia,
    descripcion,
    descripcion_adicional,
    cod_barras_1,
    cod_barras_2,
    cod_barras_3,
    brand_id,
    is_active,
    created_at,
    updated_at
)
SELECT
    public.uuid_generate_v4() AS id,                    -- ← Aquí está el uuid_generate_v4()
    cat.id AS category_id,
    sec.id AS section_id,
    sub.id AS sub_section_id,
    t.codigo,
    t.referencia,
    t.descripcion,
    t.descripcion_adicional,
    t.cod_barras_1,
    t.cod_barras_2,
    t.cod_barras_3,
    b.id AS brand_id,
    true AS is_active,
    CURRENT_TIMESTAMP AS created_at,
    CURRENT_TIMESTAMP AS updated_at
FROM public.product_migracion t
LEFT JOIN public.categories cat ON cat.nombre = t.categoria_nombre
LEFT JOIN public.sections sec   ON sec.nombre = t.seccion_nombre
LEFT JOIN public.sub_sections sub ON sub.nombre = t.subseccion_nombre
LEFT JOIN public.brands b       ON b.nombre = t.brand_nombre     -- Cambia a b.nombre si es necesario
WHERE t.referencia IS NOT NULL
  AND t.descripcion IS NOT NULL
ON CONFLICT DO NOTHING;






